(function(w){"use strict";const ID="date-add";function p(v){if(!/^\d{4}-\d{2}-\d{2}$/.test(v||""))return null;const a=v.split("-").map(Number),d=new Date(a[0],a[1]-1,a[2]);return d.getFullYear()===a[0]&&d.getMonth()===a[1]-1&&d.getDate()===a[2]?d:null}function fmt(d){return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0")}function addMonths(d,n){const day=d.getDate(),x=new Date(d.getFullYear(),d.getMonth()+n,1),last=new Date(x.getFullYear(),x.getMonth()+1,0).getDate();x.setDate(Math.min(day,last));return x}function compute(x){const d=p(x.date),amount=Number(x.amount);if(!d||!Number.isInteger(amount)||!['day','week','month','year'].includes(x.unit))return{error:"날짜와 정수 값을 올바르게 입력해 주세요."};let r=new Date(d);if(x.unit==='day')r.setDate(r.getDate()+amount);if(x.unit==='week')r.setDate(r.getDate()+amount*7);if(x.unit==='month')r=addMonths(r,amount);if(x.unit==='year')r=addMonths(r,amount*12);return{date:fmt(r)}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>기준 날짜</label><input class="hm-calc-input" type="date"></div><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>더하거나 뺄 값</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 30 또는 -30"></div><div class="hm-calc-field"><label>단위</label><select class="hm-calc-select"><option value="day">일</option><option value="week">주</option><option value="month">개월</option><option value="year">년</option></select></div></div><p class="hm-calc-hint">월·년 계산에서 해당 날짜가 존재하지 않으면 그 달의 마지막 날로 맞춥니다.</p><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">날짜 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [date,amount]=root.querySelectorAll("input"),unit=root.querySelector("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");date.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({date:date.value,amount:Number(amount.value),unit:unit.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("계산된 날짜",r.date));});}
w.HM_CALC.register(ID,{compute,render});})(window);
